from collections import defaultdict

def _dfs_cycle_util(u, parent, visited, graph):
    visited.add(u)

    for v in graph.get(u, []):
        if v not in visited:
            if _dfs_cycle_util(v, u, visited, graph):
                return True
        elif v != parent:
            return True
    return False

def detect_cycle_undirected(graph):
    visited = set()

    all_nodes = set(graph.keys())
    for neighbors in graph.values():
        all_nodes.update(neighbors)

    for node in all_nodes:
        if node not in visited:
            if _dfs_cycle_util(node, None, visited, graph):
                return True
    return False
